func submissionPreview(submission db.Submission) string {
	if len(submission.Answers) == 0 {
		return submission.AnswerSummary
	}
	value := submissionAnswerDisplay(answerDisplayValueJSON(submission.Answers[0]))
	if len([]rune(value)) > 140 {
		return string([]rune(value)[:140]) + "..."
	}
	return value
}

func answerDisplayValueJSON(answer db.SubmissionAnswer) string {
	if answer.DisplayValueJSON != "" {
		return answer.DisplayValueJSON
	}
	return answer.ValueJSON
}

func submissionAnswerDisplay(raw string) string {
	var value any
	if json.Unmarshal([]byte(raw), &value) != nil {
		return ""
	}
	switch typed := value.(type) {
	case []any:
		values := make([]string, 0, len(typed))
		for _, item := range typed {
			values = append(values, fmt.Sprint(item))
		}
		return strings.Join(values, ", ")
	default:
		return fmt.Sprint(value)
	}
}

func responseIssueURL(settings db.CampaignSettings, campaign db.Campaign, submission db.Submission) string {
	if !settings.DevFeedbackIssueURL.Valid || settings.DevFeedbackIssueURL.String == "" {
		return ""
	}
	parsed, err := url.Parse(settings.DevFeedbackIssueURL.String)
	if err != nil {
		return settings.DevFeedbackIssueURL.String
	}
	values := parsed.Query()
	if values.Get("title") == "" {
		values.Set("title", campaign.Name+": feedback "+submission.PublicID)
	}
	if values.Get("body") == "" {
		values.Set("body", responseIssueBody(campaign, submission))
	}
	parsed.RawQuery = values.Encode()
	return parsed.String()
}

func responseIssueBody(campaign db.Campaign, submission db.Submission) string {
	var body strings.Builder
	body.WriteString("Campaign: ")
	body.WriteString(campaign.Name)
	body.WriteString("\nSubmission: ")
	body.WriteString(submission.PublicID)
	body.WriteString("\nSubmitted at: ")
	body.WriteString(submission.SubmittedAt)
	body.WriteString("\nStatus: ")
	body.WriteString(submission.TriageStatus)
	body.WriteString("\n\nFeedback:\n")
	for _, answer := range submission.Answers {
		body.WriteString("\n")
		body.WriteString(answer.FieldLabelSnapshot)
		body.WriteString("\n")
		body.WriteString(submissionAnswerDisplay(answerDisplayValueJSON(answer)))
		body.WriteString("\n")
	}
	if len(submission.URLContext) > 0 {
		body.WriteString("\nContext:\n")
		for _, key := range sortedContextKeys(submission.URLContext) {
			body.WriteString(key)
			body.WriteString(": ")
			body.WriteString(submission.URLContext[key])
			body.WriteString("\n")
		}
	}
	return body.String()
}

func sortedContextKeys(values map[string]string) []string {
	keys := make([]string, 0, len(values))
	for key := range values {
		keys = append(keys, key)
	}
	sort.Strings(keys)
	return keys
}

func helpID(field db.FormField) string {
	return "help_" + field.PublicID
}

func fieldAttrs(field db.FormField) templ.Attributes {
	if field.HelpText.Valid {
		return templ.Attributes{"aria-describedby": helpID(field)}
	}
	return nil
}

